void mos6509_run(CPUState *cpu) {
    mos6509_run_until(cpu, 0);
}

void mos6509_run_until(CPUState *cpu, uint64_t cycles) {
    while (cpu->running) {
        if (cycles > 0 && cpu->total_cycles >= cycles) break;
        if (mos6509_step(cpu) != 0) break;
    }
}

/* ===== CPU Lifecycle ===== */
CPUState *mos6509_create(size_t memory_size) {
    CPUState *cpu = (CPUState *)calloc(1, sizeof(CPUState));
    if (!cpu) return NULL;
    
    cpu->memory = (uint8_t *)calloc(1, memory_size);
    if (!cpu->memory) {
        free(cpu);
        return NULL;
    }
    cpu->memory_size = memory_size;
    
    /* Initialize port memory */
    cpu->port_size = 65536;
    cpu->port_memory = (uint8_t *)calloc(1, cpu->port_size);
    
    /* Initialize hooks */
    for (int i = 0; i < (int)HOOK_COUNT; i++) {
        cpu->hooks[i].enabled = false;
        cpu->hooks[i].func = NULL;
        cpu->hooks[i].context = NULL;
    }
    /* No IC runtime configured */
    
    mos6509_reset(cpu);
    return cpu;
}

void mos6509_destroy(CPUState *cpu) {
    if (cpu) {
    /* No IC destroy hooks */
        free(cpu->memory);
        free(cpu->port_memory);
        free(cpu);
    }
}

void mos6509_reset(CPUState *cpu) {
    memset(cpu->registers, 0, sizeof(cpu->registers));
    cpu->pc = 0;
    cpu->sp = 0;
    cpu->flags.raw = 0;
    /* No shadow flag bank */
    cpu->interrupt_vector = 0;
    cpu->interrupts_enabled = false;
    cpu->interrupt_pending = false;
    /* No IC runtime configured */
    cpu->running = true;
    cpu->halted = false;
    cpu->error_code = CPU_ERROR_NONE;
    cpu->total_cycles = 0;
    cpu->pc_modified = false;
    cpu->hook_pc = 0;
    cpu->hook_prefix = 0;
    cpu->hook_opcode = 0;
    cpu->hook_raw = 0;
    cpu->tracing_enabled = false;
    cpu->debug_overlay_enabled = true;
    cpu->reset_delay_pending = true;
}

int mos6509_load_rom(CPUState *cpu, const char *filename, uint16_t address) {
    if (!cpu || !filename || !filename[0]) return -1;
    FILE *f = fopen(filename, "rb");
    if (!f) return -1;
    
    fseek(f, 0, SEEK_END);
    long size = ftell(f);
    fseek(f, 0, SEEK_SET);
    if (size < 0) {
        fclose(f);
        return -1;
    }
    
    if (address + size > cpu->memory_size) {
        fclose(f);
        return -1;
    }
    
    size_t read_len = fread(&cpu->memory[address], 1, (size_t)size, f);
    fclose(f);
    if (read_len != (size_t)size) return -1;
    snprintf(
        cpu->loaded_rom_debug,
        sizeof(cpu->loaded_rom_debug),
        "name=direct path=%s",
        filename
    );
    return 0;
}
int mos6509_load_system_roms(CPUState *cpu, const char *system_base_dir) {
    if (!cpu) return -1;
    (void)system_base_dir;
    cpu->loaded_rom_debug[0] = '\0';
    return 0;
}

int mos6509_load_cartridge_rom(CPUState *cpu, const char *path) {
    (void)cpu;
    (void)path;
    return -1;
}


/* ===== Memory Access ===== */
uint8_t mos6509_read_byte(CPUState *cpu, uint16_t addr) {

    if (addr >= cpu->memory_size) {
        cpu->error_code = CPU_ERROR_INVALID_MEMORY;
        return 0xFF;
    }
    return cpu->memory[addr];
}

void mos6509_write_byte(CPUState *cpu, uint16_t addr, uint8_t value) {

    if (addr >= cpu->memory_size) {
        cpu->error_code = CPU_ERROR_INVALID_MEMORY;
        return;
    }

    cpu->memory[addr] = value;
}

uint16_t mos6509_read_word(CPUState *cpu, uint16_t addr) {
    uint16_t lo = mos6509_read_byte(cpu, addr);
    uint16_t hi = mos6509_read_byte(cpu, addr + 1);
    return lo | (hi << 8);
}

void mos6509_write_word(CPUState *cpu, uint16_t addr, uint16_t value) {
    mos6509_write_byte(cpu, addr, value & 0xFF);
    mos6509_write_byte(cpu, addr + 1, (value >> 8) & 0xFF);
}

/* ===== Port I/O ===== */
uint8_t mos6509_read_port(CPUState *cpu, uint16_t port) {


    uint8_t value = (port < cpu->port_size) ? cpu->port_memory[port] : 0xFF;


    return value;
}

void mos6509_write_port(CPUState *cpu, uint16_t port, uint8_t value) {


    if (port >= cpu->port_size) return;
    cpu->port_memory[port] = value;


}

/* ===== Interrupts ===== */
void mos6509_interrupt(CPUState *cpu, uint8_t vector) {
    cpu->interrupt_vector = vector;
    cpu->interrupt_pending = true;
}

void mos6509_set_irq(CPUState *cpu, bool enabled) {
    cpu->interrupts_enabled = enabled;
}
/* No IC runtime API */

/* ===== Debug ===== */
void mos6509_dump_registers(CPUState *cpu) {
    printf("PC: 0x%04X SP: 0x%04X Flags: 0x%02X\n", cpu->pc, cpu->sp, cpu->flags.raw);
    for (int i = 0; i < 8; i++) {
        printf("R%d: 0x%02X ", i, cpu->registers[i]);
    }
    printf("\n");
}

void mos6509_dump_memory(CPUState *cpu, uint16_t start, uint16_t length) {
    for (uint16_t i = 0; i < length; i++) {
        if (i % 16 == 0) printf("\n%04X: ", start + i);
        printf("%02X ", cpu->memory[start + i]);
    }
    printf("\n");
}

void mos6509_dump_stack(CPUState *cpu, int depth) {
    if (depth < 0) depth = 0;
    printf("Stack from SP=0x%04X (depth=%d):\n", cpu->sp, depth);
    for (int i = 0; i < depth; i++) {
        uint16_t addr = (uint16_t)(cpu->sp + (uint16_t)i);
        if (addr >= cpu->memory_size) break;
        printf("  [%04X] = %02X\n", addr, cpu->memory[addr]);
    }
}

void mos6509_set_breakpoint(CPUState *cpu, uint16_t address) {
    if (cpu->num_break_points < 16) {
        cpu->break_points[cpu->num_break_points++] = address;
    }
}

void mos6509_clear_breakpoint(CPUState *cpu, uint16_t address) {
    for (int i = 0; i < cpu->num_break_points; i++) {
        if (cpu->break_points[i] == address) {
            for (int j = i; j < cpu->num_break_points - 1; j++) {
                cpu->break_points[j] = cpu->break_points[j + 1];
            }
            cpu->num_break_points--;
            break;
        }
    }
}

void mos6509_list_breakpoints(CPUState *cpu) {
    printf("Breakpoints (%d):\n", cpu->num_break_points);
    for (int i = 0; i < cpu->num_break_points; i++) {
        printf("  %d: 0x%04X\n", i, cpu->break_points[i]);
    }
}

void mos6509_trace_enable(CPUState *cpu, bool enable) {
    cpu->tracing_enabled = enable;
}
