void mos6509_trace_instruction(CPUState *cpu, DecodedInstruction *inst) {
    (void)cpu;
    if (!inst) return;
    uint32_t raw_for_disasm = inst->raw;
    if (inst->prefix != 0) {
        raw_for_disasm = ((uint32_t)inst->prefix) | (inst->raw << 8);
    }
    printf("[TRACE] %s\n", mos6509_disassemble_instruction(inst->pc, raw_for_disasm));
}

